&quot;); // delete ptr2; return 0;}Output:Object:Constructor !Pointer:New a pointer:Constructor !Destructor !Program ended with exit code: 0Here we can find that if we just declare a pointer, both the two functions won’t be called automatically.If you new a pointer, the constructor will be called automatically, while the destructor won’t.If you declare an object, both the two functions will be called automatically.Therefore we conclude that the automatically-called mechanism only works for objects. For pointer, sorry, you need to operate them manually.(2) Special situationsSometimes the new wine can’t be made: the minimum density is larger than the given density or the maximum density is smaller than given density. We need to deal with them seperately.My source code:#include &amp;lt;iostream&amp;gt;#include &amp;lt;iomanip&amp;gt;#include &amp;lt;vector&amp;gt;#include &amp;lt;algorithm&amp;gt;#include &amp;lt;memory&amp;gt;using namespace std;// A bottle of winetypedef pair&amp;lt;int, int&amp;gt; dpair;// Node/*********************************************** * Initialized value = 0; * Counter = 0 &amp;lt;===&amp;gt; Nope or destroyed * Counter = 1 &amp;lt;===&amp;gt; Created************************************************/struct Wine { int d, p; Wine* last; static int counter; Wine() { ++counter; } ~Wine() { --counter; }};int Wine::counter = 0;/***************************************************************** * Memory inspector, NO MODIFYING !!!! * It will be destroyed when the programme ends, * If counter != 0, it means that the wine is not destructed *****************************************************************/struct Checker { int _; ~Checker() { if (Wine::counter != 0) cout &amp;lt;&amp;lt; &quot;你的对象没有正确释放!
&quot;; }} _c;int main() { ios::sync_with_stdio(0); int n, m; vector&amp;lt;dpair&amp;gt; wines; vector&amp;lt;int&amp;gt; qs; // Input n,m and the density &amp;amp; price of each bottle of wine // Create a wine shelf cin &amp;gt;&amp;gt; n &amp;gt;&amp;gt; m; for (int i = 0; i &amp;lt; n; ++i) { int d, p; cin &amp;gt;&amp;gt; d &amp;gt;&amp;gt; p; wines.push_back(dpair(d, p)); } // Sort according to density sort(wines.begin(), wines.end()); // Create a new list Wine* phead = nullptr; Wine* temp = nullptr; for (int i = 0; i &amp;lt; n; ++i) { // Read in wine[i], you can say q = the corresponding struct node auto q = new Wine; q-&amp;gt;d = wines[i].first; q-&amp;gt;p = wines[i].second; // If two wines have the same value of d, discard the one whose q is bigger if ( phead &amp;amp;&amp;amp; phead-&amp;gt;d == q-&amp;gt;d) q-&amp;gt;~Wine(); // If phead and its tail aren&#39;t NULL while (phead != nullptr &amp;amp;&amp;amp; phead-&amp;gt;last != nullptr) { // Compare slope factor, delete the nodes away from the list // Convert the denominator to double type to avoid singular point if ((q-&amp;gt;p - phead-&amp;gt;p) / (double)(q-&amp;gt;d - phead-&amp;gt;d) &amp;lt;= (phead-&amp;gt;p - phead-&amp;gt;last-&amp;gt;p) /(double)(phead-&amp;gt;d - phead-&amp;gt;last-&amp;gt;d)){ temp = phead; phead = phead-&amp;gt;last; temp-&amp;gt;~Wine(); } else break; } // If phead isn&#39;t NULL or phead doesn&#39;t match q // The first loop go to here if (!phead || q-&amp;gt;d != phead-&amp;gt;d) { q-&amp;gt;last = phead; phead = q; } } // Use vector to search wines.clear(); for (auto i = phead; i; i = i-&amp;gt;last) { wines.push_back(dpair(i-&amp;gt;d, i-&amp;gt;p)); } // Delete the list for (auto i = phead; i; i = i-&amp;gt;last) { i-&amp;gt;~Wine(); } reverse(wines.begin(), wines.end()); cout.setf(ios::fixed); for (int i = 0; i &amp;lt; m; ++i) { int q; cin &amp;gt;&amp;gt; q; // Find the point which is the nearest to the the lowest hull // Here price is initialized to 0 if((wines[0].first &amp;gt; q) || (wines[wines.size() - 1].first &amp;lt; q)) cout &amp;lt;&amp;lt; -1 &amp;lt;&amp;lt; endl; else{ auto it = lower_bound(wines.begin(), wines.end(), dpair(q, 0)); auto ib = it - 1; double res = (it-&amp;gt;first - q) / (double)(it-&amp;gt;first - ib-&amp;gt;first) * ib-&amp;gt;second; res += (q - ib-&amp;gt;first) / (double)(it-&amp;gt;first - ib-&amp;gt;first) * it-&amp;gt;second; cout &amp;lt;&amp;lt; setprecision(2) &amp;lt;&amp;lt; res &amp;lt;&amp;lt; endl; } }}Acknowledgement:Thanks for Zhixiao Xiong(熊志潇，未央工-11)’s help, after several days’ debugging, we finally found the reason why the object couldn’t be released correctly.
